def rate_limit(max_requests=10, window_seconds=60):
    """Rate limiting decorator"""
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            user_id = request.headers.get('X-User-ID', request.remote_addr)
            current_time = datetime.now()
            
            if user_id not in rate_limit_store:
                rate_limit_store[user_id] = []
            
            # Clean old requests
            rate_limit_store[user_id] = [
                req_time for req_time in rate_limit_store[user_id]
                if current_time - req_time < timedelta(seconds=window_seconds)
            ]
            
            if len(rate_limit_store[user_id]) >= max_requests:
                return jsonify({'error': 'Rate limit exceeded'}), 429
            
            rate_limit_store[user_id].append(current_time)
            return f(*args, **kwargs)
        return wrapped
    return decorator

def token_required(f):
    """JWT authentication decorator"""
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get('Authorization')
        
        if not token:
            return jsonify({'error': 'Authentication token required'}), 401
        
        try:
            if token.startswith('Bearer '):
                token = token[7:]
            data = jwt.decode(token, app.config['JWT_SECRET'], algorithms=['HS256'])
            current_user = data['user_id']
        except jwt.ExpiredSignatureError:
            return jsonify({'error': 'Token expired'}), 401
        except jwt.InvalidTokenError:
            return jsonify({'error': 'Invalid token'}), 401
        
        return f(current_user, *args, **kwargs)
    return decorated

def validate_filename(filename: str) -> bool:
    """Validate filename against security threats"""
    if not filename or '..' in filename or '/' in filename or '\\' in filename:
        return False
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def sanitize_csv_data(df: pd.DataFrame) -> Optional[pd.DataFrame]:
    """Validate and sanitize CSV data"""
    try:
        # Check row limit
        if len(df) > MAX_CSV_ROWS:
            logger.warning(f"CSV exceeds max rows: {len(df)}")
            return None
        
        # Validate columns
        if not set(df.columns).issubset(ALLOWED_CSV_COLUMNS):
            logger.warning(f"Invalid CSV columns: {df.columns.tolist()}")
            return None
        
        # Validate labels if present
        if 'label' in df.columns:
            invalid_labels = set(df['label'].unique()) - ALLOWED_LABELS
            if invalid_labels:
                logger.warning(f"Invalid labels detected: {invalid_labels}")
                return None
        
        # Remove any potential injection attempts
        for col in df.columns:
            if df[col].dtype == 'object':
                df[col] = df[col].astype(str).str[:255]  # Limit string length
        
        return df
    except Exception as e:
        logger.error(f"CSV validation error: {str(e)}")
        return None

def validate_image(image_data: bytes) -> Optional[np.ndarray]:
    """Validate and sanitize image data"""
    try:
        # Open and validate image
        img = Image.open(io.BytesIO(image_data))
        
        # Check image size constraints
        if img.size[0] > MAX_IMAGE_SIZE[0] or img.size[1] > MAX_IMAGE_SIZE[1]:
            logger.warning(f"Image too large: {img.size}")
            return None
        
        if img.size[0] < MIN_IMAGE_SIZE[0] or img.size[1] < MIN_IMAGE_SIZE[1]:
            logger.warning(f"Image too small: {img.size}")
            return None
        
        # Convert to RGB and resize
        img = img.convert('RGB')
        img = img.resize((224, 224), Image.Resampling.LANCZOS)
        
        # Convert to array and normalize
        img_array = np.array(img, dtype=np.float32) / 255.0
        
        # Validate pixel value ranges
        if np.any(img_array < 0) or np.any(img_array > 1):
            logger.warning("Invalid pixel values detected")
            return None
        
        return img_array
    except Exception as e:
        logger.error(f"Image validation error: {str(e)}")
        return None

def detect_data_poisoning(images: np.ndarray, labels: np.ndarray) -> bool:
    """Detect potential data poisoning attempts"""
    try:
        # Check for statistical anomalies
        mean_pixel = np.mean(images)
        std_pixel = np.std(images)
        
        # Detect unusual pixel distributions
        if mean_pixel < 0.05 or mean_pixel > 0.95:
            logger.warning(f"Suspicious pixel mean: {mean_pixel}")
            return True
        
        if std_pixel < 0.01 or std_pixel > 0.5:
            logger.warning(f"Suspicious pixel std: {std_pixel}")
            return True
        
        # Check label distribution
        unique_labels, counts = np.unique(labels, return_counts=True)
        label_ratio = np.max(counts) / np.sum(counts)
        
        if label_ratio > 0.95:  # More than 95% same label
            logger.warning(f"Suspicious label distribution: {label_ratio}")
            return True
        
        return False
    except Exception as e:
        logger.error(f"Poisoning detection error: {str(e)}")
        return True  # Fail secure

