@token_required
@rate_limit(max_requests=5, window_seconds=3600)
def upload_images(current_user):
    """Upload and validate image training data"""
    try:
        if 'images' not in request.files:
            return jsonify({'error': 'No images provided'}), 400
        
        files = request.files.getlist('images')
        labels = request.form.getlist('labels')
        
        if len(files) > MAX_IMAGES_PER_UPLOAD:
            return jsonify({'error': f'Maximum {MAX_IMAGES_PER_UPLOAD} images allowed'}), 400
        
        if len(files) != len(labels):
            return jsonify({'error': 'Number of images and labels must match'}), 400
        
        validated_images = []
        validated_labels = []
        
        for file, label in zip(files, labels):
            # Validate label
            if label not in ALLOWED_LABELS:
                logger.warning(f"Invalid label: {label}")
                continue
            
            # Validate filename
            if not validate_filename(file.filename):
                logger.warning(f"Invalid filename: {file.filename}")
                continue
            
            # Validate image
            image_data = file.read()
            if len(image_data) > app.config['MAX_CONTENT_LENGTH']:
                logger.warning("Image too large")
                continue
            
            img_array = validate_image(image_data)
            if img_array is None:
                continue
            
            validated_images.append(img_array)
            validated_labels.append(label)
        
        if not validated_images:
            return jsonify({'error': 'No valid images'}), 400
        
        # Convert to numpy arrays
        images_array = np.array(validated_images)
        labels_array = np.array([list(ALLOWED_LABELS).index(l) for l in validated_labels])
        
        # Detect data poisoning
        if detect_data_poisoning(images_array, labels_array):
            logger.warning(f"Data poisoning detected from user: {current_user}")
            return jsonify({'error': 'Data validation failed - suspicious patterns detected'}), 400
        
        # Save securely
        data_id = secrets.token_hex(16)
        np.savez_compressed(
            os.path.join(app.config['UPLOAD_FOLDER'], f"{current_user}_{data_id}.npz"),
            images=images_array,
            labels=labels_array
        )
        
        logger.info(f"Images uploaded by {current_user}: {len(validated_images)} images")
        return jsonify({
            'message': 'Images uploaded successfully',
            'accepted': len(validated_images),
            'rejected': len(files) - len(validated_images),
            'data_id': data_id
        }), 200
    except Exception as e:
        logger.error(f"Image upload error: {str(e)}")
        return jsonify({'error': 'Upload failed'}), 500

@app.route('/train', methods=['POST'])
@token_required
@rate_limit(max_requests=2, window_seconds=3600)
def train_model(current_user):
    """Train model with validated data"""
    try:
        data = request.get_json()
        
        if not data or 'data_ids' not in data:
            return jsonify({'error': 'Data IDs required'}), 400
        
        data_ids = data['data_ids'][:10]  # Limit number of datasets
        
        all_images = []
        all_labels = []
        
        # Load and validate all datasets
        for data_id in data_ids:
            # Validate data_id format
            if not isinstance(data_id, str) or len(data_id) > 100:
                continue
            
            # Secure filename construction
            filename = secure_filename(f"{current_user}_{data_id}.npz")
            filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
            
            if not os.path.exists(filepath):
                logger.warning(f"Data file not found: {filename}")
                continue
            
            try:
                data = np.load(filepath)
                images = data['images']
                labels = data['labels']
                
                # Re-validate data
                if detect_data_poisoning(images, labels):
                    logger.warning(f"Poisoning detected in dataset: {data_id}")
                    continue
                
                all_images.append(images)
                all_labels.append(labels)
            except Exception as e:
                logger.error(f"Error loading dataset {data_id}: {str(e)}")
                continue
        
        if not all_images:
            return jsonify({'error': 'No valid training data'}), 400
        
        # Combine datasets
        X_train = np.concatenate(all_images)
        y_train = np.concatenate(all_labels)
        
        # Build secure model
        model = keras.Sequential([
            keras.layers.Input(shape=(224, 224, 3)),
            keras.layers.Conv2D(32, 3, activation='relu'),
            keras.layers.MaxPooling2D(),
            keras.layers.Conv2D(64, 3, activation='relu'),
            keras.layers.MaxPooling2D(),
            keras.layers.Flatten(),
            keras.layers.Dropout(0.5),
            keras.layers.Dense(128, activation='relu'),
            keras.layers.Dropout(0.5),
            keras.layers.Dense(len(ALLOWED_LABELS), activation='softmax')
        ])
        
        model.compile(
            optimizer='adam',
            loss='sparse_categorical_crossentropy',
            metrics=['accuracy']
        )
        
        # Train with validation
        history = model.fit(
            X_train, y_train,
            epochs=5,
            batch_size=32,
            validation_split=0.2,
            verbose=0
        )
        
        # Save model securely
        model_id = secrets.token_hex(16)
        model_path = os.path.join(app.config['MODEL_FOLDER'], f"{current_user}_{model_id}.h5")
        model.save(model_path)
        
        logger.info(f"Model trained by {current_user}: {model_id}")
        return jsonify({
            'message': 'Model trained successfully',
            'model_id': model_id,
            'accuracy': float(history.history['accuracy'][-1]),
            'val_accuracy': float(history.history['val_accuracy'][-1])
        }), 200
    except Exception as e:
        logger.error(f"Training error: {str(e)}")
        return jsonify({'error': 'Training failed'}), 500

